css:
body  { font-family: Arial, sans-serif; font-size: 13px; }
h1    { color: #333; border-bottom: 2px solid #4CAF50; padding-bottom: 10px; text-align: center; }
.date { background: #e8f5e9; padding: 10px; border-radius: 5px; margin-bottom: 20px; }
table { width: 100%; border-collapse: collapse; margin-top: 20px; }
th    { background-color: #4CAF50; color: white; padding: 10px; text-align: left; -webkit-print-color-adjust: exact; }
td    { padding: 9px; border-bottom: 1px solid #ddd; }
tr:nth-child(even) { background-color: #f9f9f9; }
.footer { margin-top: 20px; font-size: 11px; color: #888; text-align: right; }
